INSERT INTO sources (key, name, tier, description, applicable_entity_types, requires_identifier, provider, source_url, is_name_matched, is_active) VALUES
  ('gst_profile', 'GST registration profile', 1, 'Legal and trade name, registration date, constitution of business, and current status. A cancelled or suspended GSTIN is among the strongest single adverse signals available.', ARRAY['proprietorship', 'partnership', 'llp', 'private_limited', 'public_limited', 'huf', 'trust', 'society']::text[], 'gstin', NULL, 'https://www.gst.gov.in', false, true),
  ('gst_filing', 'GST return filing history', 1, 'GSTR-1 and GSTR-3B filing cadence by period. Monthly behavioural data requiring no consent — a contractor who stops filing is usually in trouble months before a default becomes visible anywhere else.', ARRAY['proprietorship', 'partnership', 'llp', 'private_limited', 'public_limited', 'huf', 'trust', 'society']::text[], 'gstin', NULL, 'https://www.gst.gov.in', false, true),
  ('epfo_contributions', 'EPFO establishment contributions', 1, 'Employee count and month-by-month PF contribution continuity. A business under cash pressure typically stops remitting PF before it stops paying suppliers, making a lapse here an unusually early distress indicator.', ARRAY['proprietorship', 'partnership', 'llp', 'private_limited', 'public_limited', 'huf', 'trust', 'society']::text[], 'name', NULL, 'https://www.epfindia.gov.in', true, true),
  ('litigation_cheque_bounce', 'Cheque dishonour cases (S.138 NI Act)', 1, 'District court proceedings under Section 138. The closest public analogue to payment behaviour that exists, and directly relevant to credit. Name matching is ambiguous — results are probable until disambiguated.', ARRAY['proprietorship', 'partnership', 'llp', 'private_limited', 'public_limited', 'huf', 'trust', 'society']::text[], 'name', NULL, 'https://ecourts.gov.in', true, true),
  ('litigation_recovery', 'Debt recovery and civil suits', 1, 'DRT proceedings, SARFAESI auction notices and money suits. Establishes existing recovery action by other creditors.', ARRAY['proprietorship', 'partnership', 'llp', 'private_limited', 'public_limited', 'huf', 'trust', 'society']::text[], 'name', NULL, NULL, true, true),
  ('insolvency_ibbi', 'Insolvency proceedings (IBBI / NCLT)', 1, 'Corporate debtors under CIRP and liquidation. Definitive when present.', ARRAY['proprietorship', 'partnership', 'llp', 'private_limited', 'public_limited', 'huf', 'trust', 'society']::text[], 'name', NULL, 'https://ibbi.gov.in', true, true),
  ('suit_filed_defaulters', 'Suit-filed and wilful defaulter lists', 1, 'Publicly published defaulter lists. Reporting thresholds mean most small contractors will not appear, so absence carries little weight — but presence is decisive.', ARRAY['proprietorship', 'partnership', 'llp', 'private_limited', 'public_limited', 'huf', 'trust', 'society']::text[], 'name', NULL, NULL, true, true),
  ('mca_profile', 'MCA company master data', 2, 'Incorporation date, paid-up capital, registered address, directors and current status (active, strike-off, under liquidation).', ARRAY['llp', 'private_limited', 'public_limited']::text[], 'cin', NULL, 'https://www.mca.gov.in', false, true),
  ('mca_charges', 'Registered charges', 2, 'Charges registered against the entity''s assets — how leveraged it already is, to whom, and whether those charges have been satisfied. One of the few public windows onto existing debt.', ARRAY['llp', 'private_limited', 'public_limited']::text[], 'cin', NULL, 'https://www.mca.gov.in', false, true),
  ('mca_annual_filings', 'Annual filing currency (AOC-4 / MGT-7)', 2, 'Whether statutory filings are up to date. Persistent non-filing is both a compliance signal and a common precursor to strike-off.', ARRAY['llp', 'private_limited', 'public_limited']::text[], 'cin', NULL, 'https://www.mca.gov.in', false, true),
  ('director_disqualification', 'Director disqualification list', 2, 'Directors disqualified under S.164(2). Follows the individual across entities, so it catches a promoter whose previous company failed.', ARRAY['llp', 'private_limited', 'public_limited']::text[], 'cin', NULL, 'https://www.mca.gov.in', false, true),
  ('udyam_registration', 'Udyam (MSME) registration', 2, 'Registration validity, date of commencement and declared investment/turnover bracket. Useful vintage corroboration for proprietorships, which have no registrar record.', ARRAY['proprietorship', 'partnership', 'llp', 'private_limited', 'public_limited', 'huf', 'trust', 'society']::text[], 'udyam', NULL, 'https://udyamregistration.gov.in', false, true),
  ('tender_awards', 'Government tender awards', 3, 'Contracts awarded via CPPP, GeM and state portals. Public evidence of work pipeline and operating scale — one of the few positive signals available in the public domain.', ARRAY['proprietorship', 'partnership', 'llp', 'private_limited', 'public_limited', 'huf', 'trust', 'society']::text[], 'name', NULL, 'https://eprocure.gov.in', true, true),
  ('debarment_lists', 'Debarment and blacklist entries', 3, 'Blacklisting by PSUs, government departments and public bodies. A binary disqualifier when confirmed.', ARRAY['proprietorship', 'partnership', 'llp', 'private_limited', 'public_limited', 'huf', 'trust', 'society']::text[], 'name', NULL, NULL, true, true),
  ('rera_projects', 'RERA project registrations', 3, 'Registered projects, delivery status and complaints filed, where the contractor works on real-estate projects.', ARRAY['proprietorship', 'partnership', 'llp', 'private_limited', 'public_limited', 'huf', 'trust', 'society']::text[], 'name', NULL, NULL, true, true),
  ('credit_rating', 'External credit rating', 3, 'CRISIL, ICRA, CARE and India Ratings publications. Most small contractors are unrated, but a published rating rationale is unusually rich when one exists.', ARRAY['proprietorship', 'partnership', 'llp', 'private_limited', 'public_limited', 'huf', 'trust', 'society']::text[], 'name', NULL, NULL, true, true)
